#include <bits/stdc++.h>
using namespace std;
map<string,int> mp;
int t,s;
int main(){
    scanf("%d",&t);
    while(t--){
        int op;
        scanf("%d",&op);
        if(op==1){
            string name;
            int score;
            cin>>name>>score;
            printf("OK\n");
            if(!mp[name])
                s++;
            mp[name]=score;
        }else if(op==2){
            string name;
            cin>>name;
            if(!mp[name])
                printf("Not found\n");
            else
                printf("%d\n",mp[name]);
        }else if(op==3){
            string name;
            cin>>name;
            if(!mp[name])
                printf("Not found\n");
            else{
                s--;
                mp[name]=0;
                printf("Deleted successfully\n");
            }
        }else if(op==4)
            printf("%d\n",s);
    }
    return 0;
}
